export function isMobileDevice() {
  var isMobileDevice = /iPhone|iPad|iPod|Android|webOS|BlackBerry|Windows Phone/i.test(navigator.userAgent);
  return isMobileDevice;
}

export function getThreatDrillKey(threat, isDrill) {
  return threat + "|" + (isDrill ? "true" : "false");
}

export function decodeThreatDrillKey(key) {
  const [threat, drill] = key.split("|");
  return [Number(threat), drill === "true" ? true : false];
}

