export function getColorForThreat(threat) {
  switch (threat) {
    case 0:
      return "#A52A2A";
    case 2:
      return "rgb(255, 213, 0)";
    case 3:
      return "rgb(0, 255, 85)";
    case 4:
      return "rgb(0, 128, 255)";
    case 5:
      return "rgb(255, 128, 0)";
    default:
      return "#A52A2A";
  }
}
